    const tip = await getAIExplanation(solver, solver.stepDescription);
    setAiTip(tip);
    setLoadingAi(false);
  };

  // --- Render Helpers ---

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans selection:bg-indigo-100 flex flex-col">
