                              >
                                 <ArrowRight className="w-5 h-5" /> 
                                 {solver.status === 'ready' ? '计算位势 (逐步)' :
                                  solver.status === 'potentials' ? '计算检验数 (逐步)' :
                                  solver.status === 'deltas' ? '寻找闭回路 (逐步)' :
                                  '调整运量 (逐步)'}
                              </button>

                              {/* Iteration Shortcuts */}
                              {(solver.status === 'ready' || solver.status === 'input') && (
                                <div className="grid grid-cols-2 gap-2 mt-1">
                                    <button 
