            ...prev, grid: cleanGrid,
            u: new Array(problem.rowCount).fill(null), v: new Array(problem.colCount).fill(null),
            status: 'ready', iteration: currentIteration + 1, totalCost: newCost,
            message: `迭代 ${currentIteration + 1} 准备就绪`,
            stepDescription: `调整量 θ=${theta}，新运费 ${newCost}。`
        }));
        addLog(currentIteration, "调整", `运费降至 ${newCost}`, 'info', newCost);
    }
  };

  const handleAutoSolve = () => {
      setIsAutoSolving(true);
      if (solver.status === 'input') handleStart();
  };

  const askAI = async () => {
    setLoadingAi(true);
    const tip = await getAIExplanation(solver, solver.stepDescription);
    setAiTip(tip);
    setLoadingAi(false);
  };

