  const apiKey = userApiKey || process.env.API_KEY;

  if (!apiKey) {
      return "请先在右上角【设置】中输入 API Key 才能使用 AI 解释功能。";
  }

  const gridSummary = state.grid.map(row => 
    row.map(c => `(${c.row},${c.col}): 运价=${c.cost}, 分配量=${c.allocation ?? 0}, 基变量=${c.isBasin}, 检验数=${c.opportunityCost ?? 'N/A'}`).join(' | ')
  ).join('\n');

  const prompt = `
    你是一位运筹学助教。请用简洁的中文（3句以内）解释当前步骤。

    上下文: ${context}
    状态: ${state.status}
    迭代: ${state.iteration}
    当前总运费: ${state.totalCost}

    表格数据:
    ${gridSummary}

    重点解释：为什么这样做？这对降低运费有什么帮助？
  `;

  try {
    if (provider === 'deepseek') {
        const response = await fetch('https://api.deepseek.com/chat/completions', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${apiKey}`
            },
            body: JSON.stringify({
                model: 'deepseek-chat',
                messages: [
                    { role: "system", content: "你是一位专业的运筹学专家。" },
                    { role: "user", content: prompt }
                ],
                stream: false
            })
        });

        if (!response.ok) {
            const err = await response.json();
            throw new Error(err.error?.message || 'DeepSeek 请求失败');
        }

        const data = await response.json();
        return data.choices?.[0]?.message?.content || "无回复";

    } else {
        // Default to Gemini
        const ai = new GoogleGenAI({ apiKey });
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: prompt,
        });

        return response.text || "无法生成解释。";
    }
  } catch (error: any) {
    console.error("AI Error:", error);
    return `AI 请求出错: ${error.message}`;
  }
};

