import React, { useState, useEffect, useRef } from 'react';
import Tableau from './components/Tableau';
import { ProblemState, SolverState, LogEntry } from './types';
import { solveLeastCost, calculatePotentials, calculateOpportunityCosts, findLoop, applyPivot, generateRandomProblem, createEmptyGrid, calculateTotalCost } from './utils/solver';
import { getAIExplanation } from './services/geminiService';
import { Play, RotateCcw, Brain, CheckCircle, ChevronRight, PlayCircle, PauseCircle, SkipForward } from 'lucide-react';
import clsx from 'clsx';

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const App: React.FC = () => {
  // --- Config & Settings ---
  const [config, setConfig] = useState({ rows: 3, cols: 4 });

  // --- Problem State ---
  const [problem, setProblem] = useState<ProblemState | null>(null);
  const [solver, setSolver] = useState<SolverState>({
    grid: [], u: [], v: [], totalCost: 0,
    status: 'input', message: "就绪", stepDescription: "点击“生成新问题”开始。", iteration: 0
  });

  const [history, setHistory] = useState<LogEntry[]>([]);
  const [aiTip, setAiTip] = useState<string>("");
  const [loadingAi, setLoadingAi] = useState(false);
  const [isAutoSolving, setIsAutoSolving] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto Scroll History
  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [history]);

  // Auto Solve Timer
  useEffect(() => {
    let timer: number;
    if (isAutoSolving && solver.status !== 'optimal') {
      if(solver.status === 'input') {
          handleStart();
      } else {
          timer = window.setTimeout(() => handleNextIteration(), 1000);
      }
    } else if (solver.status === 'optimal') {
      setIsAutoSolving(false);
    }
    return () => clearTimeout(timer);
  }, [isAutoSolving, solver.status]);

  // --- Logic ---
  const addLog = (desc: string, type: 'info' | 'success' | 'warning' | 'error' = 'info') => {
    setHistory(p => [...p, {
      id: Date.now(), iteration: solver.iteration, phase: solver.status, description: desc, cost: solver.totalCost, type
    }]);
  };

  const handleGenerate = () => {
    setIsAutoSolving(false);
    const p = generateRandomProblem(config.rows, config.cols);
    setProblem(p);
    const empty = createEmptyGrid(p.rowCount, p.colCount, p.costs);
    setSolver({
      grid: empty, u: Array(p.rowCount).fill(null), v: Array(p.colCount).fill(null),
      totalCost: 0, status: 'input', message: "新问题已生成", stepDescription: "等待初始解生成...", iteration: 0
    });
    setHistory([]);
    setAiTip("");
  };

  const handleStart = () => {
    if (!problem) return;
    const initialGrid = solveLeastCost(problem);
    const cost = calculateTotalCost(initialGrid);
    setSolver({
      grid: initialGrid, u: Array(problem.rowCount).fill(null), v: Array(problem.colCount).fill(null),
      totalCost: cost, status: 'ready', message: "初始基可行解", stepDescription: "最小元素法生成。", iteration: 1
    });
    addLog("生成初始解 (最小元素法)", 'info');
  };

  const handleNextStep = () => {
    if (!problem) return;
    setSolver(prev => {
      let next = { ...prev };
      switch (prev.status) {
        case 'ready':
          const { u, v } = calculatePotentials(prev.grid, problem.rowCount, problem.colCount);
          next.u = u; next.v = v; next.status = 'potentials';
          next.message = "计算位势"; next.stepDescription = "计算行位势 u 和列位势 v。";
          return next;
        case 'potentials':
          const { grid: g1, minDelta, enteringCell } = calculateOpportunityCosts(prev.grid, prev.u, prev.v);
          if (minDelta >= 0) {
            next.grid = g1; next.status = 'optimal'; next.message = "最优解"; next.stepDescription = "所有检验数非负。";
            addLog("找到最优解", 'success');
          } else {
            if(enteringCell) g1[enteringCell.r][enteringCell.c].highlight = 'entering';
            next.grid = g1; next.status = 'deltas'; next.message = "检验数判断"; next.stepDescription = `发现负检验数 ${minDelta}，需调整。`;
          }
          return next;
        case 'deltas':
          let en = {r:-1, c:-1};
          prev.grid.forEach(r => r.forEach(c => { if(c.highlight==='entering') en={r:c.row, c:c.col}; }));
          const loop = findLoop(en, prev.grid);
          if(loop) {
            const g2 = prev.grid.map(r => r.map(c => ({...c})));
            loop.forEach((n,i) => { if(i>0) g2[n.r][n.c].highlight = i%2===0?'loop-plus':'loop-minus'; });
            next.grid = g2; next.status = 'loop'; next.message = "闭回路"; next.stepDescription = "构建调整闭回路。";
          }
          return next;
        case 'loop':
          let en2 = {r:-1, c:-1};
          prev.grid.forEach(r => r.forEach(c => { if(c.highlight==='entering') en2={r:c.row, c:c.col}; }));
          const loop2 = findLoop(en2, prev.grid);
          if(loop2) {
             const { newGrid, theta } = applyPivot(prev.grid, loop2);
             const cost = calculateTotalCost(newGrid);
             const clean = newGrid.map(r => r.map(c => ({...c, opportunityCost:undefined, highlight:'none' as const})));
             next.grid = clean; next.totalCost = cost; next.u = Array(problem.rowCount).fill(null); next.v = Array(problem.colCount).fill(null);
             next.status = 'ready'; next.iteration = prev.iteration+1; next.message = "调整完成"; next.stepDescription = `调整量 ${theta}, 运费降至 ${cost}。`;
             addLog(`迭代完成，运费: ${cost}`, 'info');
          }
          return next;
        default: return prev;
      }
    });
  };

  const handleNextIteration = async () => {
     if(!problem) return;
     if(solver.status === 'input') { handleStart(); return; }

     // Perform full logic manually for "Skip Iteration" feel
     const current = solver.grid;
     const { u, v } = calculatePotentials(current, problem.rowCount, problem.colCount);
     const { grid: g1, minDelta, enteringCell } = calculateOpportunityCosts(current, u, v);

     if (minDelta >= 0) {
        setSolver(prev => ({...prev, grid: g1, u, v, status: 'optimal', message: "最优解", stepDescription: "最优解已达成。"}));
        addLog("最优解达成", 'success');
        return;
     }

     if (enteringCell) {
         const loop = findLoop(enteringCell, g1);
         if (loop) {
             const { newGrid, theta } = applyPivot(g1, loop);
             const cost = calculateTotalCost(newGrid);
             const clean = newGrid.map(r => r.map(c => ({...c, opportunityCost:undefined, highlight:'none' as const})));

             setSolver(prev => ({
                 ...prev, grid: clean, totalCost: cost, iteration: prev.iteration + 1,
                 status: 'ready', message: `迭代 ${prev.iteration + 1}`, stepDescription: `调整量 ${theta}，新运费 ${cost}`
             }));
             // Fix: Use solver.iteration since prev is not accessible here
             addLog(`迭代 ${solver.iteration} 完成 (Cost: ${cost})`, 'info');
         }
     }
  };

  const askAI = async () => {
      setLoadingAi(true);
      const res = await getAIExplanation(solver, solver.stepDescription);
      setAiTip(res);
      setLoadingAi(false);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans text-gray-800">

      {/* 1. Header */}
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between sticky top-0 z-50">
         <div className="flex items-center gap-3">
             <div className="bg-indigo-600 text-white p-1.5 rounded">
                <Brain className="w-5 h-5" />
             </div>
             <h1 className="text-xl font-bold tracking-tight text-gray-900">运筹学求解器 <span className="text-gray-400 font-normal text-sm">| AI 辅助</span></h1>
         </div>
         <div className="flex items-center gap-4">
             {problem && (
                 <div className="flex gap-4 text-sm font-mono bg-gray-100 px-4 py-1.5 rounded-full">
                    <span>Iter: <b>{solver.iteration}</b></span>
                    <span className="text-indigo-600">Cost: <b>¥{solver.totalCost}</b></span>
                 </div>
             )}
         </div>
      </header>

      {/* 2. Main Content */}
      <main className="flex-1 flex overflow-hidden">

         {/* Left: Visualization */}
         <div className="flex-1 p-6 overflow-auto bg-gray-50 flex flex-col items-center">
            {problem ? (
               <div className="w-full max-w-5xl">
                  <Tableau solverState={solver} problem={problem} />

                  {/* Control Bar (Standard) */}
                  <div className="mt-8 bg-white p-4 rounded-xl shadow-sm border border-gray-200 flex flex-wrap items-center justify-center gap-4">
                     <button onClick={() => setIsAutoSolving(!isAutoSolving)} disabled={solver.status==='optimal'} className={clsx("flex items-center gap-2 px-6 py-2 rounded-lg font-bold text-white transition-colors", isAutoSolving ? "bg-amber-500 hover:bg-amber-600" : "bg-indigo-600 hover:bg-indigo-700 disabled:bg-gray-300")}>
                        {isAutoSolving ? <PauseCircle className="w-5 h-5"/> : <PlayCircle className="w-5 h-5"/>}
                        {isAutoSolving ? "暂停" : "自动求解"}
                     </button>
                     <div className="w-px h-8 bg-gray-200 mx-2"></div>
                     <button onClick={handleNextStep} disabled={isAutoSolving || solver.status==='optimal'} className="px-4 py-2 bg-white border border-gray-300 hover:bg-gray-50 rounded-lg text-sm font-medium flex items-center gap-2">
                        <ChevronRight className="w-4 h-4"/> 单步
                     </button>
                     <button onClick={handleNextIteration} disabled={isAutoSolving || solver.status==='optimal'} className="px-4 py-2 bg-white border border-gray-300 hover:bg-gray-50 rounded-lg text-sm font-medium flex items-center gap-2">
                        <SkipForward className="w-4 h-4"/> 跳过本轮
                     </button>
                     <button onClick={handleGenerate} className="px-4 py-2 text-rose-600 hover:bg-rose-50 rounded-lg text-sm font-medium flex items-center gap-2 ml-auto">
                        <RotateCcw className="w-4 h-4"/> 重置
                     </button>
                  </div>
               </div>
            ) : (
               <div className="mt-20 text-center bg-white p-10 rounded-2xl shadow-sm border border-gray-200 max-w-md">
                  <h2 className="text-2xl font-bold mb-4">开始新的问题</h2>
                  <div className="flex justify-center gap-8 mb-8">
                      <label className="flex flex-col">
                          <span className="text-sm text-gray-500 font-bold mb-2">产地数</span>
                          <input type="number" value={config.rows} onChange={e=>setConfig(c=>({...c, rows:+e.target.value}))} className="w-20 p-2 border rounded text-center font-bold"/>
                      </label>
                      <label className="flex flex-col">
                          <span className="text-sm text-gray-500 font-bold mb-2">销地数</span>
                          <input type="number" value={config.cols} onChange={e=>setConfig(c=>({...c, cols:+e.target.value}))} className="w-20 p-2 border rounded text-center font-bold"/>
                      </label>
                  </div>
                  <button onClick={handleGenerate} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-colors">生成并开始</button>
               </div>
            )}
         </div>

         {/* Right: Sidebar */}
         <div className="w-80 bg-white border-l border-gray-200 flex flex-col shrink-0">
            {/* Status Panel */}
            <div className="p-5 border-b border-gray-100">
               <h3 className="text-xs font-bold text-gray-400 uppercase mb-3">当前状态</h3>
               <div className="text-sm text-gray-700 font-medium bg-gray-50 p-3 rounded-lg border border-gray-100">
                  <div className="flex items-center gap-2 text-indigo-600 mb-1">
                     <CheckCircle className="w-4 h-4"/>
                     <span className="font-bold">{solver.message}</span>
                  </div>
                  <p className="text-gray-500 text-xs leading-relaxed">{solver.stepDescription}</p>
               </div>
            </div>

            {/* AI Panel */}
            <div className="flex-1 flex flex-col min-h-0 border-b border-gray-100">
               <div className="p-3 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
                  <span className="text-xs font-bold text-gray-500 flex items-center gap-2"><Brain className="w-3 h-3"/> AI 解析</span>
                  <span className="text-[10px] px-2 py-0.5 rounded bg-indigo-100 text-indigo-600 font-bold">Gemini 2.5</span>
               </div>
               <div className="flex-1 p-4 overflow-y-auto bg-gray-50/50">
                  {aiTip ? (
                     <div className="text-sm text-gray-700 leading-relaxed bg-white p-3 rounded-lg shadow-sm border border-gray-100">{aiTip}</div>
                  ) : (
                     <div className="text-center text-gray-400 text-xs mt-10">点击下方按钮获取分析</div>
                  )}
               </div>
               <div className="p-4 bg-white">
                  <button onClick={askAI} disabled={loadingAi || !problem} className="w-full py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 disabled:opacity-50 transition-colors flex items-center justify-center gap-2">
                     {loadingAi ? "分析中..." : "解释当前步骤"}
                  </button>
               </div>
            </div>

            {/* Log Panel */}
            <div className="h-1/3 flex flex-col bg-white">
               <div className="p-3 border-b border-gray-100 text-xs font-bold text-gray-400 uppercase">操作日志</div>
               <div className="flex-1 overflow-y-auto p-2 space-y-1" ref={scrollRef}>
                  {history.map(h => (
                     <div key={h.id} className="text-xs p-2 rounded hover:bg-gray-50 flex justify-between">
                        <span className="text-gray-600">{h.description}</span>
                        <span className="font-mono font-bold text-gray-400">¥{h.cost}</span>
                     </div>
                  ))}
               </div>
            </div>
         </div>
      </main>

    </div>
  );
};

