import { GoogleGenAI } from "@google/genai";
import { SolverState } from "../types";

export const getAIExplanation = async (
  state: SolverState,
  context: string
): Promise<string> => {

  // Directly use process.env.API_KEY as per coding guidelines
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
      return "Environment variable API_KEY is not configured.";
  }

  const gridSummary = state.grid.map(row => 
    row.map(c => `(${c.row},${c.col}): 运价=${c.cost}, 分配量=${c.allocation ?? 0}, 基变量=${c.isBasin}, 检验数=${c.opportunityCost ?? 'N/A'}`).join(' | ')
  ).join('\n');

  const prompt = `
    你是一位运筹学助教。请用简洁的中文（3句以内）解释当前步骤。

    上下文: ${context}
    状态: ${state.status}
    迭代: ${state.iteration}
    当前总运费: ${state.totalCost}

    表格数据:
    ${gridSummary}

    重点解释：为什么这样做？这对降低运费有什么帮助？
  `;

  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text || "无法生成解释。";
  } catch (error: any) {
    console.error("AI Error:", error);
    return `AI 请求出错: ${error.message}`;
  }
};

